toolArgs.file_text:
@page "/inventory"
@using sv_c3bdd3a643c54ee99cd1383656e8296d.Models
@using sv_c3bdd3a643c54ee99cd1383656e8296d.Services
@inject InventoryService InventoryService
@inject NavigationManager Navigation

<PageTitle>Inventory</PageTitle>

<h1>Inventory Management</h1>

<!-- MODE 1: Static SSR Quick Add Form -->
<div class="card mb-4">
    <div class="card-header">
        <h5 class="mb-0">Quick Add Product</h5>
    </div>
    <div class="card-body">
        <EditForm Model="NewProduct" FormName="QuickAddProduct" method="post" OnValidSubmit="HandleAddProduct">
            <DataAnnotationsValidator />
            <ValidationSummary />
            <div class="row g-3 align-items-end">
                <div class="col-md-3">
                    <label class="form-label">Name</label>
                    <InputText class="form-control" @bind-Value="NewProduct.Name" />
                </div>
                <div class="col-md-2">
                    <label class="form-label">Quantity</label>
                    <InputNumber class="form-control" @bind-Value="NewProduct.Quantity" />
                </div>
                <div class="col-md-2">
                    <label class="form-label">Unit Price</label>
                    <InputNumber class="form-control" @bind-Value="NewProduct.UnitPrice" />
                </div>
                <div class="col-md-3">
                    <label class="form-label">Category</label>
                    <InputSelect class="form-select" @bind-Value="NewProduct.Category">
                        <option value="">-- Select --</option>
                        <option value="Electronics">Electronics</option>
                        <option value="Clothing">Clothing</option>
                        <option value="Food">Food</option>
                        <option value="Other">Other</option>
                    </InputSelect>
                </div>
                <div class="col-md-2">
                    <button type="submit" class="btn btn-primary w-100">Add</button>
                </div>
            </div>
        </EditForm>
    </div>
</div>

<!-- MODE 2: Product Table with Inline Editing -->
<div class="card">
    <div class="card-header">
        <h5 class="mb-0">Products</h5>
    </div>
    <div class="card-body p-0">
        <table class="table table-striped mb-0">
            <thead>
                <tr>
                    <th>Name</th>
                    <th>Quantity</th>
                    <th>Unit Price</th>
                    <th>Category</th>
                    <th>Actions</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var product in Products)
                {
                    @if (EditingProductId == product.Id)
                    {
                        <EditRow Product="product"
                                 OnSave="HandleSave"
                                 OnCancel="HandleCancel"
                                 @rendermode="InteractiveServer" />
                    }
                    else
                    {
                        <tr>
                            <td>@product.Name</td>
                            <td>@product.Quantity</td>
                            <td>@product.UnitPrice.ToString("C")</td>
                            <td>@product.Category</td>
                            <td>
                                <a href="/inventory?edit=@product.Id" class="btn btn-sm btn-outline-secondary">Edit</a>
                            </td>
                        </tr>
                    }
                }
            </tbody>
        </table>
    </div>
</div>

@code {
    [SupplyParameterFromForm]
    private Product NewProduct { get; set; } = new();

    [SupplyParameterFromQuery(Name = "edit")]
    private int? EditingProductId { get; set; }

    private List<Product> Products { get; set; } = new();

    protected override async Task OnInitializedAsync()
    {
        Products = await InventoryService.GetAllAsync();
    }

    private async Task HandleAddProduct()
    {
        await InventoryService.AddAsync(NewProduct);
        Navigation.NavigateTo("/inventory", forceLoad: true);
    }

    private async Task HandleSave(Product product)
    {
        await InventoryService.UpdateAsync(product);
        Navigation.NavigateTo("/inventory", forceLoad: true);
    }

    private void HandleCancel()
    {
        Navigation.NavigateTo("/inventory", forceLoad: true);
    }
}

@using sv_c3bdd3a643c54ee99cd1383656e8296d.Models
@using sv_c3bdd3a643c54ee99cd1383656e8296d.Services
@inject InventoryService InventoryService

<tr>
    <EditForm Model="EditModel" OnValidSubmit="Save" class="contents">
        <DataAnnotationsValidator />
        <td>
            <InputText class="form-control form-control-sm" @bind-Value="EditModel.Name" />
            <ValidationMessage For="() => EditModel.Name" />
        </td>
        <td>
            <InputNumber class="form-control form-control-sm" @bind-Value="EditModel.Quantity" />
            <ValidationMessage For="() => EditModel.Quantity" />
        </td>
        <td>
            <InputNumber class="form-control form-control-sm" @bind-Value="EditModel.UnitPrice" />
            <ValidationMessage For="() => EditModel.UnitPrice" />
        </td>
        <td>
            <InputSelect class="form-select form-select-sm" @bind-Value="EditModel.Category">
                <option value="">-- Select --</option>
                <option value="Electronics">Electronics</option>
                <option value="Clothing">Clothing</option>
                <option value="Food">Food</option>
                <option value="Other">Other</option>
            </InputSelect>
            <ValidationMessage For="() => EditModel.Category" />
        </td>
        <td>
            <button type="submit" class="btn btn-sm btn-success me-1">Save</button>
            <button type="button" class="btn btn-sm btn-secondary" @onclick="Cancel">Cancel</button>
        </td>
    </EditForm>
</tr>

@code {
    [Parameter]
    public Product Product { get; set; } = default!;

    [Parameter]
    public EventCallback<Product> OnSave { get; set; }

    [Parameter]
    public EventCallback OnCancel { get; set; }

    private Product EditModel { get; set; } = new();

    protected override void OnParametersSet()
    {
        // Copy values so edits don't mutate the original until Save
        EditModel = new Product
        {
            Id = Product.Id,
            Name = Product.Name,
            Quantity = Product.Quantity,
            UnitPrice = Product.UnitPrice,
            Category = Product.Category
        };
    }

    private async Task Save()
    {
        await OnSave.InvokeAsync(EditModel);
    }

    private async Task Cancel()
    {
        await OnCancel.InvokeAsync();
    }
}

